INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('6239e9bc-db3f-51e6-8cbd-d9ee35caa025', 'ddd11e86-f590-4ee4-8317-e17a7de6e3eb', 'The talented ___ gave a powerful performance that moved the entire audience to tears.', '那位才華橫溢的男演員帶來了強而有力的表演，令全場觀眾感動落淚。', 'actor', 'chef', 'pilot', 'lawyer', 'act (做、行動) + -or (表示人的字尾) → 演員', '記住 act 是「行動」的意思，加上 -or 變成「做動作的人」，即演員。', '2026-07-06 17:26:18', '2026-07-06 17:26:18'),
('23fc6296-12b6-5079-9915-b9f69a4b3269', '87d28373-2f85-4fc4-bb02-62dfc40f21be', 'After hours of intense negotiation, the two companies finally reached an ___ regarding the new partnership.', '經過數小時激烈的談判，這兩家公司終於就新的合作夥伴關係達成了協議。', 'agreement', 'argument', 'ability', 'attitude', 'agree (同意) + -ment (名詞字尾) → agreement (同意、協議)', '想像兩個人在點頭表示 agree，加上字尾 -ment 變成名詞 agreement。', '2026-07-06 19:18:03', '2026-07-06 19:18:03'),
('061db0ab-0cfb-5048-ab04-b2145c178525', '6a32b5ab-bc4b-468c-978e-6c871955f3d0', 'The government is investing more resources into the ___ sector to modernize farming techniques.', '政府正投入更多資源於農業部門，以實現耕作技術的現代化。', 'agricultural', 'commercial', 'medical', 'political', '字根 agri- 表示「田地」或「土地」，-cultural 則與耕作、文化有關，組合起來即為「農業的」。', 'agri (土地) → agricultural (農業的)', '2026-07-06 19:18:58', '2026-07-06 19:18:58'),
('52160397-fecc-544c-868b-cb428b2c7651', 'ad1de4c8-bcbd-4de0-ace8-daddde72c056', 'The ___ production was charmingly simple, lacking the polish of a big-budget Hollywood movie.', '這部業餘製作雖然簡單得可愛，但缺乏好萊塢大片那種精緻感。', 'amateur', 'expensive', 'sudden', 'annual', '源自法文 aimer (愛)，原意指因為熱愛某事而參與，而非為了謀生，故引申為「業餘的」或「外行的」。', 'amateur 聯想 ''am'' (愛) → 因為愛好才去做的人 → 業餘愛好者。', '2026-07-06 20:33:39', '2026-07-06 20:33:39'),
('14a7ff81-ffcc-57a6-9850-49f9b986b0c1', 'df3b25a9-fb2b-45dc-8e2e-bf5fb50ea736', 'Can you ___ my question?', '你可以回答我的問題嗎？', 'answer', 'forget', 'bring', 'sleep', 'answer 為動詞，表示回答。', '看到 question (問題) 就要找 answer (回答)。', '2026-07-06 14:19:54', '2026-07-06 14:19:54'),
('8a839f30-f6bf-5ad4-86fc-5d6ec0721af9', '642f2b3c-b853-439b-98b0-1023ba701b6e', 'The teacher gave an ___ example that made the complex scientific concept very easy to understand.', '老師舉了一個恰當的例子，使得那個複雜的科學概念變得非常容易理解。', 'apt', 'vague', 'brief', 'harsh', '源自拉丁語 aptus，意為適合或結合。', '可以將 apt 與 appropriate 聯想，兩者都有恰當、適合的意思。', '2026-07-06 23:33:58', '2026-07-06 23:33:58'),
('7a35cc88-f96a-5693-804e-b94cccd1ebc5', 'b44b804e-27d7-4622-ae2e-0256d4aac781', '___ the sun began to set, the temperature dropped rapidly.', '當太陽開始下山時，氣溫迅速下降。', 'As', 'Although', 'Unless', 'Whether', 'As 在此作為連接詞，用來引導時間子句。', 'As + 子句 → 當...的時候', '2026-07-07 00:37:30', '2026-07-07 00:37:30'),
('c2a8af4d-c928-580b-9e07-56ff05b4d6c9', 'f5c12b94-81b6-4e19-af50-cf7696b09f2a', 'The ___ gives us fresh milk every morning.', '母牛每天早上都給我們新鮮的牛奶。', 'cow', 'pig', 'duck', 'sheep', 'cow 為基本單字，指母牛。', '想像一頭會說 ''Moo~'' 且會產牛奶的黑白斑點動物就是 cow。', '2026-07-07 10:52:42', '2026-07-07 10:52:42'),
('517638ba-81d3-552b-b621-51fef3db006d', '1ec4a2b2-701f-4b78-bb8c-d2705e93a5d9', 'She doesn''t know how to ___ with her angry boss.', '她不知道該如何應對她憤怒的老闆。', 'deal', 'sleep', 'dance', 'sing', 'deal with 為固定片語，意為「處理」或「應付」。', '想像面對問題時，你需要 deal (處理) 好手邊的事情。', '2026-07-07 02:58:09', '2026-07-07 02:58:09'),
('4ee3b36b-118d-5d17-8fd1-50ee823050ed', '781bbbf4-2cba-4f0e-b2e8-1c06d866a9ea', 'Chocolate cake is my favorite ___.', '巧克力蛋糕是我最喜歡的餐後甜點。', 'dessert', 'song', 'color', 'sport', 'dessert 指的是餐後甜點。', '兩個 s 代表甜點很 Sweet。', '2026-07-07 03:41:56', '2026-07-07 03:41:56'),
('d4476df3-6116-5e06-ab46-8fcad101ced1', '117d6c68-fa48-4e08-8873-814c3d283aef', 'My grandfather is ___ years old.', '我的祖父今年八十歲。', 'eighty', 'hungry', 'happy', 'tall', 'eight (八) 加上字尾 -y 變成 eighty (八十的)。', '記住 eight 是 8，加上 y 就變成 80。', '2026-07-07 03:29:02', '2026-07-07 03:29:02'),
('cd0a95c0-7101-5548-8bb2-7789777fb1c5', 'dade2ef5-eb2a-4b08-b1be-122388cdcf93', 'Please use the nearest ___ to leave the building.', '請使用最近的出口離開這棟建築物。', 'exit', 'window', 'ceiling', 'floor', 'ex- 表示「向外」，ire 表示「走」。', 'ex 代表 out (出)，it 代表 go (走) → exit 就是「走出去」的意思。', '2026-07-07 05:16:46', '2026-07-07 05:16:46'),
('ca8119ba-cdcf-512e-bead-96e58f0a53f1', '57167f8f-e0a4-4930-9e71-cfcc9c532bdb', 'You must ___ out this application form.', '你必須填寫這份申請表。', 'fill', 'take', 'make', 'give', 'fill out 是一個片語，意思是「填寫」。', '把空格「填滿」就是填寫。', '2026-07-07 11:52:36', '2026-07-07 11:52:36'),
('b3c83d60-b7af-5090-a601-820f75741a51', '0a9d1fff-48a1-407a-8876-f4f1e5167e0a', 'Where did you ___ that beautiful shell?', '你在哪裡發現那個漂亮的貝殼的？', 'find', 'eat', 'swim', 'read', 'find 為動詞，意為「發現」。', 'find → 發現 (find an answer 找到答案)', '2026-07-07 11:56:30', '2026-07-07 11:56:30'),
('016ae8bb-485a-5f5b-8da0-824d72d83299', '58e8d447-6562-4df8-adc8-9dc7157d066f', 'He gave a ___ answer about what happened.', '他對發生的事情給了一個坦白的回答。', 'frank', 'loud', 'long', 'fast', 'frank 為單字本身，表示「坦白的」。', '想像 Frank 是一個說話很直、很坦白的人。', '2026-07-07 12:51:54', '2026-07-07 12:51:54'),
('32cad3d6-14aa-5028-8ea8-71aee545bcb9', 'e2105252-0775-4ce8-a1c3-3bc5863e63c3', 'The teacher will ___ our homework after class.', '老師會在下課後幫我們改作業。', 'grade', 'sing', 'cook', 'jump', 'grade 作為動詞時，表示將事物進行分等級或評分。', '老師在改作業時，會把分數 grade 一個一個給出來。', '2026-07-08 06:14:14', '2026-07-08 06:14:14'),
('ae8229b9-1df3-5a41-a128-5a068c664a69', '18f8e0d3-9a13-4323-81ef-3408271ccc7b', 'The trees in the park ___ taller every year.', '公園裡的樹每年都長得更高。', 'grow', 'run', 'sleep', 'dance', 'grow 指的是生物的「成長」或植物的「生長」。', '想像樹木從地底向上「長」出來的樣子。', '2026-07-07 14:04:39', '2026-07-07 14:04:39'),
('2f2ea599-81cf-59df-a778-ae80cfe96f8d', '69c72296-40c5-4d3c-8b3a-6a62df6576c3', '___ ambition is to become a famous scientist and win a Nobel Prize.', '我的志向是成為一名著名的科學家並獲得諾貝爾獎。', 'My', 'Your', 'Her', 'Their', '所有格形容詞 (possessive adjective)', 'my + 名詞 → 我的...', '2026-07-05 14:13:13', '2026-07-05 14:13:13'),
('28ae8e17-5733-582d-bc51-05cc7fa96249', '20d6333f-d9da-4330-b0cf-8ed640c01ec4', 'Please give this gift ___ my mother.', '請把這份禮物給我的母親。', 'to', 'with', 'for', 'from', '表示動作的「對象」。', 'give...to... → 給某人', '2026-07-05 09:19:21', '2026-07-05 09:19:21');
